 3→export const toggleReactionController = async (req, res) => {
 4→    try {
 5→        const { journalId, receiverId, reactionType } = req.body;
 6→        const senderId = req.userId;
 7→
 8→        if (!journalId || !reactionType) {
 9→            return res.status(400).json({ error: 'journalId and reactionType are required' });
10→        }
11→
12→        const result = await toggleReactionService(journalId, receiverId || senderId, senderId, reactionType);
13→        return res.status(200).json(result);
14→    } catch (err) {
15→        console.error('error in toggleReactionController:', err);
16→        const status = err?.status || 500;
17→        return res.status(status).json({ error: err?.error || 'failed to toggle reaction' });
18→    }
19→};
