21→export const getPostReactionsController = async (req, res) => {
22→    try {
23→        const { journalId } = req.params;
24→        if (!journalId) {
25→            return res.status(400).json({ error: 'journalId is required' });
26→        }
27→
28→        const result = await getPostReactionsService(journalId);
29→        return res.status(200).json(result);
30→    } catch (err) {
31→        console.error('error in getPostReactionsController:', err);
32→        const status = err?.status || 500;
33→        return res.status(status).json({ error: err?.error || 'failed to get reactions' });
34→    }
