 1→import React from 'react';
 2→import { motion, AnimatePresence } from 'framer-motion';
 3→import { REACTION_TYPES } from '../../utils/reactionConfig';
 4→import './reactions.css';
 5→
 6→const ReactionPicker = ({ isOpen, onSelect, currentReaction }) => {
 7→    return (
 8→        <AnimatePresence>
 9→            {isOpen && (
10→                <motion.div
11→                    className="reaction-picker"
12→                    initial={{ opacity: 0, scale: 0.8, y: 8 }}
13→                    animate={{ opacity: 1, scale: 1, y: 0 }}
14→                    exit={{ opacity: 0, scale: 0.8, y: 8 }}
15→                    transition={{ type: 'spring', damping: 20, stiffness: 400 }}
16→                >
17→                    {REACTION_TYPES.map((reaction, index) => (
18→                        <motion.button
19→                            key={reaction.type}
20→                            className={`reaction-picker-item ${currentReaction === reaction.type ? 'is-active' : ''}`}
21→                            onClick={(e) => {
22→                                e.preventDefault();
23→                                e.stopPropagation();
24→                                onSelect(reaction.type);
25→                            }}
26→                            title={reaction.label}
27→                            initial={{ opacity: 0, y: 10 }}
28→                            animate={{ opacity: 1, y: 0 }}
29→                            transition={{ delay: index * 0.03 }}
30→                            whileHover={{ scale: 1.4 }}
31→                            whileTap={{ scale: 0.9 }}
32→                        >
33→                            {reaction.emoji}
34→                        </motion.button>
35→                    ))}
36→                </motion.div>
37→            )}
38→        </AnimatePresence>
39→    );
40→};
41→
42→export default ReactionPicker;
