  1→import React, { useState, useRef, useCallback } from 'react';
  2→import ReactionPicker from './ReactionPicker';
  3→import { getReactionEmoji } from '../../utils/reactionConfig';
  4→import './reactions.css';
  5→
  6→const ReactionButton = ({ userReaction, reactionCount, onReact, disabled }) => {
  7→    const [showPicker, setShowPicker] = useState(false);
  8→    const hoverTimerRef = useRef(null);
  9→    const longPressTimerRef = useRef(null);
 10→    const containerRef = useRef(null);
 11→
 12→    const handleMouseEnter = useCallback(() => {
 13→        hoverTimerRef.current = setTimeout(() => {
 14→            setShowPicker(true);
 15→        }, 300);
 16→    }, []);
 17→
 18→    const handleMouseLeave = useCallback(() => {
 19→        if (hoverTimerRef.current) {
 20→            clearTimeout(hoverTimerRef.current);
 21→            hoverTimerRef.current = null;
 22→        }
 23→        setShowPicker(false);
 24→    }, []);
 25→
 26→    const handleTouchStart = useCallback(() => {
 27→        longPressTimerRef.current = setTimeout(() => {
 28→            setShowPicker(true);
 29→        }, 500);
 30→    }, []);
 31→
 32→    const handleTouchEnd = useCallback(() => {
 33→        if (longPressTimerRef.current) {
 34→            clearTimeout(longPressTimerRef.current);
 35→            longPressTimerRef.current = null;
 36→        }
 37→    }, []);
 38→
 39→    const handleQuickClick = useCallback((e) => {
 40→        e.preventDefault();
 41→        e.stopPropagation();
 42→        if (disabled) return;
 43→
 44→        if (showPicker) {
 45→            setShowPicker(false);
 46→            return;
 47→        }
 48→
 49→        // Quick tap: toggle heart (or remove current reaction)
 50→        if (userReaction) {
 51→            onReact(userReaction); // toggle off
 52→        } else {
 53→            onReact('heart'); // default to heart
 54→        }
 55→    }, [userReaction, onReact, disabled, showPicker]);
 56→
 57→    const handlePickerSelect = useCallback((reactionType) => {
 58→        setShowPicker(false);
 59→        onReact(reactionType);
 60→    }, [onReact]);
 61→
 62→    const hasReaction = !!userReaction;
 63→    const displayEmoji = hasReaction ? getReactionEmoji(userReaction) : null;
 64→
 65→    return (
 66→        <div
 67→            className="reaction-button-container"
 68→            ref={containerRef}
 69→            onMouseEnter={handleMouseEnter}
 70→            onMouseLeave={handleMouseLeave}
 71→            onTouchStart={handleTouchStart}
 72→            onTouchEnd={handleTouchEnd}
 73→        >
 74→            <div
 75→                className={`reaction-button ${hasReaction ? 'has-reaction' : ''}`}
 76→                onClick={handleQuickClick}
 77→            >
 78→                {hasReaction ? (
 79→                    <span className="reaction-button-emoji">{displayEmoji}</span>
 80→                ) : (
 81→                    <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
 82→                        <g id="style=fill">
 83→                        <g id="like">
 84→                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M15.9977 5.63891C16.2695 4.34931 15.433 3.00969 14.2102 2.59462C13.6171 2.37633 12.9892 2.4252 12.4662 2.60499C11.9449 2.78419 11.4461 3.12142 11.1369 3.58441L11.136 3.58573L7.49506 9.00272C8.05104 9.29585 8.43005 9.87954 8.43005 10.5518V21.3018H6.91003V21.3018H16.6801C18.2938 21.3018 19.2028 20.2977 19.8943 19.202C20.6524 18.0009 21.1453 16.7211 21.5116 15.5812C21.6808 15.0546 21.8252 14.5503 21.9547 14.0984L21.9863 13.9881C22.126 13.5007 22.2457 13.0904 22.366 12.7549C22.698 11.8292 22.5933 10.9072 22.067 10.2072C21.5476 9.5166 20.7005 9.15175 19.76 9.15175H15.76C15.6702 9.15175 15.6017 9.11544 15.5599 9.06803C15.5238 9.02716 15.4831 8.95058 15.502 8.81171L15.9977 5.63891Z" fill="#5e5e5eff"/>
 85→                        <path id="rec" d="M2.18005 10.6199C2.18005 10.03 2.62777 9.55176 3.18005 9.55176H6.68005C7.23234 9.55176 7.68005 10.03 7.68005 10.6199V21.3018H3.18005C2.62777 21.3018 2.18005 20.8235 2.18005 20.2336V10.6199Z" fill="#5e5e5eff"/>
 86→                        </g>
 87→                        </g>
 88→                    </svg>
 89→                )}
 90→            </div>
 91→            {typeof reactionCount === 'number' && reactionCount > 0 && (
 92→                <span className="reaction-count">{reactionCount}</span>
 93→            )}
 94→            <ReactionPicker
 95→                isOpen={showPicker}
 96→                onSelect={handlePickerSelect}
 97→                currentReaction={userReaction}
 98→            />
 99→        </div>
100→    );
101→};
102→
103→export default ReactionButton;
